This function is supposed to check whether a filename ends with `.cpp`. What is the bug?

```cpp
#include <iostream>
#include <string>
#include <string_view>

bool isCppFile(std::string_view name) {
    return name.ends_with(".cpp");
}

int main() {
    std::string file{ "main.cpp" };
    std::string_view sv{ file };
    file += "x";      // rename to main.cppx
    std::cout << isCppFile(sv) << '\n';
}
```

