Which of the following is a safe use of `std::string_view`?

```cpp
// Option A
std::string_view sv;
{
    std::string tmp{ "hello" };
    sv = tmp;
} // tmp destroyed here
std::cout << sv;

// Option B
void print(std::string_view sv) {
    std::cout << sv;
}
std::string s{ "hello" };
print(s);  // s still alive
```
